import { describe, expect, test } from "bun:test"
import { existsSync, readFileSync } from "node:fs"
import { join } from "node:path"

const DEMO_ROOT = join(import.meta.dir, "../../../")
const REQUIRED_RPC_URL = "https://starknet-mainnet.public.blastapi.io"

function readDemoFile(relativePath: string): string {
  return readFileSync(join(DEMO_ROOT, relativePath), "utf-8")
}

function readDemoJson(relativePath: string): unknown {
  return JSON.parse(readDemoFile(relativePath))
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null && !Array.isArray(value)
}

function getObject(source: unknown, key: string): Record<string, unknown> {
  if (!isRecord(source)) {
    return {}
  }

  const value = source[key]
  if (!isRecord(value)) {
    return {}
  }

  return value
}

function getStringArray(value: unknown): ReadonlyArray<string> {
  if (!Array.isArray(value)) {
    return []
  }

  return value.filter((entry): entry is string => typeof entry === "string")
}

describe("ES-001 scaffold contract: .env.local", () => {
  test(".env.local exists", () => {
    expect(existsSync(join(DEMO_ROOT, ".env.local"))).toBe(true)
  })

  test(".env.local contains NEXT_PUBLIC_STARKNET_RPC_URL with expected value", () => {
    const lines = readDemoFile(".env.local")
      .split(/\r?\n/)
      .map((line) => line.trim())
      .filter((line) => line.length > 0)

    const rpcEntry = lines.find((line) => line.startsWith("NEXT_PUBLIC_STARKNET_RPC_URL="))

    expect(rpcEntry).toBeDefined()

    if (rpcEntry === undefined) {
      return
    }

    const value = rpcEntry.slice("NEXT_PUBLIC_STARKNET_RPC_URL=".length)
    expect(value).toBe(REQUIRED_RPC_URL)
  })
})

describe("ES-001 scaffold contract: tsconfig", () => {
  test("tsconfig has Next plugin", () => {
    const tsconfig = readDemoJson("tsconfig.json")
    const compilerOptions = getObject(tsconfig, "compilerOptions")
    const plugins = compilerOptions["plugins"]

    const hasNextPlugin =
      Array.isArray(plugins) &&
      plugins.some((entry) => isRecord(entry) && entry["name"] === "next")

    expect(hasNextPlugin).toBe(true)
  })

  test("tsconfig include contains required Next entries", () => {
    const tsconfig = readDemoJson("tsconfig.json")
    const include = isRecord(tsconfig) ? getStringArray(tsconfig["include"]) : []

    expect(include).toContain("next-env.d.ts")
    expect(include).toContain(".next/types/**/*.ts")
  })
})

describe("ES-001 scaffold contract: required dependencies", () => {
  test("effect-service dependencies are installed", () => {
    const packageJson = readDemoJson("package.json")
    const dependencies = getObject(packageJson, "dependencies")

    const requiredDependencies = [
      "effect",
      "@effect-atom/atom",
      "@effect-atom/atom-react",
      "starknet",
    ]

    for (const dependency of requiredDependencies) {
      expect(typeof dependencies[dependency]).toBe("string")
    }
  })
})

