import { describe, expect, test } from "bun:test"
import { existsSync, readFileSync } from "node:fs"
import { join } from "node:path"

const DEMO_ROOT = join(import.meta.dir, "../../../")
const PROVIDER_PATH = join(DEMO_ROOT, "src/providers/AtomProvider.tsx")

function readProviderFile(): string {
  return readFileSync(PROVIDER_PATH, "utf-8")
}

describe("AtomProvider module contract", () => {
  test("provider module exists at src/providers/AtomProvider.tsx", () => {
    expect(existsSync(PROVIDER_PATH)).toBe(true)
  })

  test("provider is a client component", () => {
    expect(existsSync(PROVIDER_PATH)).toBe(true)
    if (!existsSync(PROVIDER_PATH)) {
      return
    }

    const content = readProviderFile().trimStart()
    const hasUseClient =
      content.startsWith('"use client"') || content.startsWith("'use client'")

    expect(hasUseClient).toBe(true)
  })

  test("provider wraps children with the atom-react registry provider", () => {
    expect(existsSync(PROVIDER_PATH)).toBe(true)
    if (!existsSync(PROVIDER_PATH)) {
      return
    }

    const content = readProviderFile()
    const hasRegistryProviderImport =
      /import\s*\{\s*RegistryProvider(?:\s+as\s+BaseAtomProvider)?\s*\}\s*from\s*"@effect-atom\/atom-react"/.test(
        content,
      )
    const wrapsChildren =
      /<\s*(?:BaseAtomProvider|RegistryProvider)\s*>\s*\{children\}\s*<\/\s*(?:BaseAtomProvider|RegistryProvider)\s*>/s.test(
        content,
      )

    expect(hasRegistryProviderImport).toBe(true)
    expect(wrapsChildren).toBe(true)
  })

  test("exports AtomProvider with expected signature contract", () => {
    expect(existsSync(PROVIDER_PATH)).toBe(true)
    if (!existsSync(PROVIDER_PATH)) {
      return
    }

    const content = readProviderFile()
    expect(content).toContain(
      "export function AtomProvider({ children }: { children: React.ReactNode })",
    )
  })
})

